import '../lib/connectivity_monitor.dart';
import '../lib/epoch_filter.dart';
import '../lib/lease_pool.dart';
import '../lib/source.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final leases = LeasePool();
  leases.add('summary');
  leases.add('editor');
  leases.remove('editor');
  check(leases.transportWanted, 'the summary lease remains live after editor exit');
  leases.remove('summary');
  check(!leases.transportWanted, 'an empty lease set releases transport');

  final epochs = EpochFilter();
  final suspendedToken = epochs.open();
  epochs.close();
  final resumedToken = epochs.open();
  check(!epochs.accepts(suspendedToken), 'suspended callbacks stay retired');
  check(epochs.accepts(resumedToken), 'resumed callbacks use the active token');

  final source = ManualStatusSource();
  final monitor = ConnectivityMonitor(source);
  final firstRoute = <String>[];
  final handoffRoute = <String>[];

  monitor.attach('dashboard', firstRoute.add);
  final retiredLater = source.bindings.single;
  retiredLater.deliverLive('lan');
  monitor.attach('details', handoffRoute.add);
  check(handoffRoute.join('|') == 'lan', 'route handoff starts from current state');

  monitor.detach('dashboard');
  check(!retiredLater.isClosed, 'the details lease retains the shared binding');
  retiredLater.deliverLive('roaming');
  check(
    handoffRoute.join('|') == 'lan|roaming',
    'the surviving route sees the next transition',
  );

  monitor.detach('details');
  check(retiredLater.isClosed, 'the source closes once the lease set is empty');
  final resumedRoute = <String>[];
  monitor.attach('resumed', resumedRoute.add);
  check(
    resumedRoute.join('|') == 'roaming',
    'resume exposes the last accepted state immediately',
  );
  source.bindings.last.deliverLive('offline');
  retiredLater.deliverQueued('lan');
  check(
    resumedRoute.join('|') == 'roaming|offline',
    'retired queued work cannot leak across a full lifecycle boundary',
  );
}
